mapper.select:
SELECT FROM cart c JOIN sku s ON c.sku_id = s.id JOIN product p ON s.product_id = p.id LEFT JOIN merchant m ON p.merchant_id = m.id LEFT JOIN distributor_product dp ON dp.id = c.distributor_product_id LEFT JOIN merchant_distribution_product mdp ON mdp.id = dp.distribution_product_id LEFT JOIN distributor d ON d.id = dp.distributor_id WHERE c.user_id = #{userId} AND c.id IN
#{cartItemId}
ORDER BY c.id DESC

mapper.update:
UPDATE cart
SET quantity = #{quantity},
    distributor_product_id = #{distributorProductId},
    attribution_expires_at = #{attributionExpiresAt}
WHERE id = #{id} AND user_id = #{userId}

mapper.delete:
DELETE FROM cart
WHERE user_id = #{userId}
  AND id IN

    #{cartItemId}
